"""Minimal MCP HTTP interface.Exposes MCP tools via a simple FastAPI endpoint.This is intentionally thin:- No auth- No protocol complexity- Just a clean wrapper around call_tool()"""from fastapi import FastAPI, HTTPExceptionfrom pydantic import BaseModelfrom typing import Any, Dictfrom apps.mcp.mcp_server import call_toolapp = FastAPI(title="MCP API", version="0.1.0")# -------------------------# Request / Response models# -------------------------class MCPRequest(BaseModel):    name: str    args: Dict[str, Any]class MCPResponse(BaseModel):    status: str    result: Any# -------------------------# Endpoints# -------------------------@app.get("/health")def health():    return {"ok": True}@app.post("/mcp/call_tool", response_model=MCPResponse)def call_tool_endpoint(req: MCPRequest):    try:        result = call_tool(req.name, req.args)        return MCPResponse(            status="success",            result=result,        )    except Exception as e:        raise HTTPException(            status_code=500,            detail=f"Tool execution failed: {str(e)}"        )